<?php $__env->startSection('content'); ?><section class="page-hero"><div class="container"><span class="eyebrow">Help centre</span><h1>Questions before the confetti.</h1><p>Booking, payment, city coverage and service information.</p></div></section><section class="section"><div class="container narrow-content"><?php $__currentLoopData = $faqs; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $group=>$items): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); ?><div class="section-heading text-start mb-3"><span><?php echo e($group); ?></span><h2><?php echo e(\Illuminate\Support\Str::headline($group)); ?></h2></div><div class="accordion mb-5" id="faqGroup<?php echo e($loop->index); ?>"><?php $__currentLoopData = $items; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $faq): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); ?><div class="accordion-item"><h3 class="accordion-header"><button class="accordion-button collapsed" data-bs-toggle="collapse" data-bs-target="#faqItem<?php echo e($faq->id); ?>"><?php echo e($faq->question); ?></button></h3><div id="faqItem<?php echo e($faq->id); ?>" class="accordion-collapse collapse" data-bs-parent="#faqGroup<?php echo e($loop->parent->index); ?>"><div class="accordion-body"><?php echo e($faq->answer); ?></div></div></div><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); ?></div><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); ?></div></section><?php $__env->stopSection(); ?>

